esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to service-level request counters (counter requires TS + INCREASE)
| WHERE traefik_service_requests_total IS NOT NULL
// Aggregate total and 5xx requests per service over the time window
| STATS
    total = SUM(traefik_service_requests_total),
    errors_5xx = SUM(traefik_service_requests_total) WHERE attributes.code LIKE "5*"
  BY attributes.service
// Minimum sample size to avoid noisy low-traffic services; adjust based on expected volume
| WHERE total > 100
// Calculate error rate as percentage
| EVAL error_rate_pct = ROUND(errors_5xx / total * 100.0, 2)
// Alert threshold: tune for sensitivity (e.g. 5.0 = 5%)
| WHERE error_rate_pct > 5.0
| SORT error_rate_pct DESC
| LIMIT 10
